formSettings.onAfterDataLoad:
const load = async () => {
  try {
    const res = await http.get('/api/services/AssetManagement/VerificationCampaign/GetDashboardSummaryList');
    const items = (res.data && res.data.result) || [];
    const s = items[0] || {};
    form.setFormData({ values: {
      kpiCampaignCount: String(s.campaignCount || 0),
      kpiAssetsScanned: (s.assetsScanned || 0).toLocaleString(),
      kpiExceptionsOpen: String(s.exceptionsOpen || 0),
      kpiDevicesActive: (s.devicesActive || 0) + ' / ' + (s.devicesTotal || 0)
    }, mergeValues: true });
  } catch (e) { console.error('KPI load failed', e); }
};
return load();
